# WhyVec CMake/Ninja demo repository

This is the canonical synthetic product demonstration. It is a real multi-file
CMake project with a public header, a C implementation, an FFI-style wrapper,
and tests covering both ordinary disjoint inputs and a bound pointer that
overlaps writable output.

Configure it with Clang 21 and an exported compilation database:

```console
CC=clang-21 cmake -S demo -B demo/build -G Ninja \
  -DCMAKE_BUILD_TYPE=Release -DCMAKE_EXPORT_COMPILE_COMMANDS=ON
cmake --build demo/build
ctest --test-dir demo/build --output-on-failure
```

The selected loop is `src/kernel.c:4`. The public/FFI boundary deliberately
prevents caller discovery from authorizing a global `restrict` contract.
cmake_minimum_required(VERSION 3.20)
project(whyvec_demo C)

set(CMAKE_C_STANDARD 17)
set(CMAKE_C_STANDARD_REQUIRED ON)
set(CMAKE_EXPORT_COMPILE_COMMANDS ON)

add_library(whyvec_demo STATIC
    src/kernel.c
    src/ffi.c
)
target_include_directories(whyvec_demo PUBLIC include)
target_compile_options(whyvec_demo PRIVATE -O3 -march=x86-64-v3)

enable_testing()
add_executable(whyvec_demo_test tests/test_kernel.c)
target_link_libraries(whyvec_demo_test PRIVATE whyvec_demo)
add_test(NAME whyvec_demo_test COMMAND whyvec_demo_test)
#ifndef WHYVEC_DEMO_H
#define WHYVEC_DEMO_H

void add_vectors_(int *output, const int *input, const int *count);

/* FFI-style entry point. External callers are intentionally not closed-world. */
void whyvec_demo_apply(int *output, const int *input, const int *count);

#endif
#include "whyvec_demo.h"

void add_vectors_(int *output, const int *input, const int *count) {
  for (int i = 0; i < *count; ++i) {
    output[i] += input[i];
  }
}
#include "whyvec_demo.h"

void whyvec_demo_apply(int *output, const int *input, const int *count) {
  add_vectors_(output, input, count);
}
#include "whyvec_demo.h"

#include <assert.h>

static void test_disjoint(void) {
  int output[] = {1, 2, 3, 4};
  const int input[] = {10, 20, 30, 40};
  const int count = 4;
  whyvec_demo_apply(output, input, &count);
  assert(output[0] == 11 && output[3] == 44);
}

static void test_bound_overlaps_output(void) {
  int output[] = {1, 2, 3, 3, 9};
  const int input[] = {1, 1, -2, 100, 100};
  add_vectors_(output, input, &output[2]);
  assert(output[0] == 2);
  assert(output[1] == 3);
  assert(output[2] == 1);
  assert(output[3] == 3);
}

int main(void) {
  test_disjoint();
  test_bound_overlaps_output();
  return 0;
}

